"""Tenant-neutral repair intake cards used to seed the business knowledge base.

These cards describe symptoms and useful follow-up questions. They deliberately
do not diagnose a failed component or promise that a specific repair is offered.
"""


def _card(question, variants, answer, group):
    return {
        "question": question,
        "variants": variants,
        "answer": answer,
        "category": f"Приймання: {group}",
    }


